{
  "name": "Somiddho Smart Scanner",
  "description": "An AI-powered QR code scanner and generator with advanced analysis capabilities using Gemini.",
  "requestFramePermissions": [
    "camera"
  ]
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum View {
  SCANNER = 'SCANNER',
  GENERATOR = 'GENERATOR',
  HISTORY = 'HISTORY',
  SETTINGS = 'SETTINGS'
}

export enum QRType {
  URL = 'URL',
  WIFI = 'WIFI',
  TEXT = 'TEXT',
  CONTACT = 'CONTACT',
  WHATSAPP = 'WHATSAPP'
}

export interface ScanResult {
  id: string;
  data: string;
  timestamp: number;
  type: string;
  analysis?: string;
  imageUrl?: string;
}

export interface QRConfig {
  type: QRType;
  value: string;
  color: string;
  logoUrl?: string;
  frameStyle: string;
}

import React, { useState, useEffect } from 'react';
import { View, ScanResult } from './types';
import ScannerView from './components/ScannerView';
import GeneratorView from './components/GeneratorView';
import HistoryView from './components/HistoryView';
import SettingsView from './components/SettingsView';
import Layout from './components/Layout';

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<View>(View.SCANNER);
  const [history, setHistory] = useState<ScanResult[]>([]);
  const [isDarkMode, setIsDarkMode] = useState(true);

  // Load history from local storage on mount
  useEffect(() => {
    const savedHistory = localStorage.getItem('somiddho_history');
    if (savedHistory) {
      setHistory(JSON.parse(savedHistory));
    }
  }, []);

  // Save history to local storage when it changes
  useEffect(() => {
    localStorage.setItem('somiddho_history', JSON.stringify(history));
  }, [history]);

  const addScanResult = (result: ScanResult) => {
    setHistory(prev => [result, ...prev].slice(0, 50));
  };

  const renderView = () => {
    switch (currentView) {
      case View.SCANNER:
        return <ScannerView onResult={addScanResult} lastScan={history[0]} />;
      case View.GENERATOR:
        return <GeneratorView />;
      case View.HISTORY:
        return <HistoryView history={history} clearHistory={() => setHistory([])} />;
      case View.SETTINGS:
        return <SettingsView isDarkMode={isDarkMode} setIsDarkMode={setIsDarkMode} />;
      default:
        return <ScannerView onResult={addScanResult} lastScan={history[0]} />;
    }
  };

  return (
    <Layout currentView={currentView} setView={setCurrentView}>
      {renderView()}
    </Layout>
  );
};

export default App;

