import { GoogleGenAI } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export async function analyzeScannedContent(content: string, imageUrl?: string) {
  if (!process.env.API_KEY) return "AI analysis unavailable - API Key not set.";

  try {
    const prompt = `Analyze this content scanned from a QR code: "${content}". 
    Provide a concise, helpful summary or safety warning. 
    If it's a URL, tell me what it likely points to. 
    If it's WiFi info, explain its purpose. 
    Be professional and brief.`;

    if (imageUrl) {
        // Multi-modal analysis if we have an image
        const response = await ai.models.generateContent({
            model: 'gemini-3-flash-preview',
            contents: {
                parts: [
                    { inlineData: { mimeType: 'image/jpeg', data: imageUrl.split(',')[1] } },
                    { text: prompt }
                ]
            }
        });
        return response.text || "Analyzed successfully.";
    } else {
        const response = await ai.models.generateContent({
            model: 'gemini-3-flash-preview',
            contents: prompt,
        });
        return response.text || "Analyzed successfully.";
    }
  } catch (error) {
    console.error("Gemini Analysis Error:", error);
    return "Failed to analyze content with AI.";
  }
}

import React, { useRef, useEffect, useState, useCallback } from 'react';
import { ScanResult } from '../types';
import { analyzeScannedContent } from '../services/geminiService';

interface ScannerViewProps {
  onResult: (result: ScanResult) => void;
  lastScan?: ScanResult;
}

const ScannerView: React.FC<ScannerViewProps> = ({ onResult, lastScan }) => {
  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [stream, setStream] = useState<MediaStream | null>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [flashOn, setFlashOn] = useState(false);
  const [batchMode, setBatchMode] = useState(false);
  const [zoom, setZoom] = useState(1);

  useEffect(() => {
    async function setupCamera() {
      try {
        const mediaStream = await navigator.mediaDevices.getUserMedia({
          video: { facingMode: 'environment', zoom: zoom as any }
        });
        setStream(mediaStream);
        if (videoRef.current) {
          videoRef.current.srcObject = mediaStream;
        }
      } catch (err) {
        console.error("Camera access error:", err);
      }
    }

    setupCamera();

    return () => {
      if (stream) {
        stream.getTracks().forEach(track => track.stop());
      }
    };
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [zoom]);

  const captureFrame = useCallback(() => {
    if (!videoRef.current || !canvasRef.current) return null;
    const canvas = canvasRef.current;
    const video = videoRef.current;
    canvas.width = video.videoWidth;
    canvas.height = video.videoHeight;
    const ctx = canvas.getContext('2d');
    if (ctx) {
      ctx.drawImage(video, 0, 0, canvas.width, canvas.height);
      return canvas.toDataURL('image/jpeg', 0.8);
    }
    return null;
  }, []);

  const handleManualScan = async () => {
    setIsAnalyzing(true);
    const imageData = captureFrame();

    // In a real app, you'd use a QR library here. 
    // For this demo, we simulate finding data "somiddho.com/pro/active"
    const mockData = "https://somiddho.com/api/v1/auth/session_8829";

    const analysis = await analyzeScannedContent(mockData, imageData || undefined);

    const result: ScanResult = {
      id: Date.now().toString(),
      data: mockData,
      timestamp: Date.now(),
      type: 'URL',
      analysis,
      imageUrl: imageData || undefined
    };

    onResult(result);
    setIsAnalyzing(false);
  };

  return (
    <div className="relative h-full flex flex-col">
      {/* Background Camera Feed */}
      <div className="absolute inset-0 z-0 bg-black">
        <video 
          ref={videoRef} 
          autoPlay 
          playsInline 
          className="w-full h-full object-cover opacity-60 grayscale-[0.3]"
        />
        <canvas ref={canvasRef} className="hidden" />
        <div className="absolute inset-0 bg-gradient-to-b from-background-dark/80 via-transparent to-background-dark/90"></div>
      </div>

      {/* Top Controls */}
      <header className="relative z-10 px-6 py-4 flex flex-col gap-6">
        <div className="flex items-center justify-between">
          <div className="flex items-center gap-3">
            <div className="w-10 h-10 rounded-xl bg-primary flex items-center justify-center shadow-[0_0_15px_rgba(19,146,236,0.4)]">
              <span className="material-icons-round text-white">qr_code_scanner</span>
            </div>
            <div>
              <h1 className="text-xl font-bold tracking-tight">Somiddho</h1>
              <p className="text-[10px] uppercase tracking-widest text-primary/80 font-semibold">Pro Scanner v3.0</p>
            </div>
          </div>
          <div className="flex items-center gap-2 glass-panel p-1 rounded-full">
            <button 
              onClick={() => setFlashOn(!flashOn)}
              className={`w-10 h-10 flex items-center justify-center rounded-full transition-colors ${flashOn ? 'bg-primary/20 text-primary' : 'hover:bg-white/10'}`}
            >
              <span className="material-icons-round">{flashOn ? 'flash_on' : 'flash_off'}</span>
            </button>
            <button className="w-10 h-10 flex items-center justify-center rounded-full hover:bg-white/10 transition-colors">
              <span className="material-icons-round">info_outline</span>
            </button>
          </div>
        </div>

        <div className="flex items-center justify-between gap-4">
          <div className="flex-1 flex items-center gap-4 glass-panel px-4 py-3 rounded-2xl">
            <span className="material-icons-round text-primary text-sm">zoom_in</span>
            <input 
              type="range" 
              min="1" 
              max="10" 
              step="0.1"
              value={zoom}
              onChange={(e) => setZoom(parseFloat(e.target.value))}
              className="flex-1 accent-primary h-1.5 bg-white/20 rounded-full appearance-none cursor-pointer" 
            />
            <span className="text-xs font-medium text-white/60">{zoom.toFixed(1)}x</span>
          </div>
          <div className="flex items-center gap-3 glass-panel px-4 py-3 rounded-2xl">
            <span className="text-xs font-bold uppercase tracking-wider text-white/70">Batch</span>
            <button 
              onClick={() => setBatchMode(!batchMode)}
              className={`relative inline-flex items-center h-6 w-11 rounded-full transition-colors ${batchMode ? 'bg-primary' : 'bg-white/20'}`}
            >
              <span className={`inline-block w-4 h-4 transform bg-white rounded-full transition-transform ${batchMode ? 'translate-x-6' : 'translate-x-1'}`} />
            </button>
          </div>
        </div>
      </header>

      {/* Viewfinder */}
      <main className="relative z-10 flex-1 flex flex-col items-center justify-center px-8">
        <div className="absolute top-0 transform -translate-y-12 bg-primary/20 border border-primary/40 px-4 py-1.5 rounded-full backdrop-blur-md">
          <div className="flex items-center gap-2">
            <div className={`w-2 h-2 rounded-full bg-primary ${isAnalyzing ? 'animate-ping' : 'animate-pulse'}`}></div>
            <span className="text-xs font-bold text-white tracking-widest uppercase">
              {isAnalyzing ? 'Analyzing with AI...' : batchMode ? 'Batch Mode Active' : 'Ready to Scan'}
            </span>
          </div>
        </div>

        <div className="relative w-full max-w-xs aspect-square cursor-pointer" onClick={handleManualScan}>
          <div className="hud-corner top-0 left-0 border-t-4 border-l-4 rounded-tl-xl"></div>
          <div className="hud-corner top-0 right-0 border-t-4 border-r-4 rounded-tr-xl"></div>
          <div className="hud-corner bottom-0 left-0 border-b-4 border-l-4 rounded-bl-xl"></div>
          <div className="hud-corner bottom-0 right-0 border-b-4 border-r-4 rounded-br-xl"></div>
          <div className="scanner-line"></div>
          <div className="absolute inset-0 flex items-center justify-center opacity-20">
            <span className="material-icons-round text-6xl">filter_center_focus</span>
          </div>
        </div>

        <p className="mt-12 text-center text-white/60 text-sm font-medium tracking-wide">
          Tap frame or align QR code to scan
        </p>
      </main>

      {/* Footer Controls */}
      <footer className="relative z-10 p-6 space-y-6">
        <div className="flex items-end justify-between gap-4">
          <button className="group flex flex-col items-center gap-2">
            <div className="w-14 h-14 glass-panel rounded-2xl flex items-center justify-center group-hover:bg-primary/20 transition-all border-white/10">
              <span className="material-icons-round text-white/80">photo_library</span>
            </div>
            <span className="text-[10px] font-bold uppercase tracking-widest text-white/50">Gallery</span>
          </button>

          {lastScan && (
            <div className="flex-1 max-w-[200px] glass-panel p-3 rounded-2xl flex items-center gap-3 border-primary/20 shadow-lg shadow-black/50 animate-in slide-in-from-bottom-2 duration-300">
              <div className="w-12 h-12 rounded-lg bg-primary/20 overflow-hidden flex-shrink-0 relative flex items-center justify-center">
                {lastScan.imageUrl ? (
                  <img src={lastScan.imageUrl} className="w-full h-full object-cover" alt="Last Scan" />
                ) : (
                  <span className="material-icons-round text-primary">qr_code</span>
                )}
              </div>
              <div className="flex-1 min-w-0">
                <p className="text-[10px] text-primary font-bold uppercase tracking-tighter">Recent Scan</p>
                <p className="text-xs font-medium truncate">{lastScan.data}</p>
                <p className="text-[9px] text-white/40">{new Date(lastScan.timestamp).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}</p>
              </div>
            </div>
          )}

          <button className="group flex flex-col items-center gap-2">
            <div className="w-14 h-14 glass-panel rounded-2xl flex items-center justify-center group-hover:bg-primary/20 transition-all border-white/10">
              <span className="material-icons-round text-white/80">auto_awesome</span>
            </div>
            <span className="text-[10px] font-bold uppercase tracking-widest text-white/50">Smart</span>
          </button>
        </div>
      </footer>
    </div>
  );
};

export default ScannerView;

import React, { useState } from 'react';
import { QRType } from '../types';

const GeneratorView: React.FC = () => {
  const [type, setType] = useState<QRType>(QRType.URL);
  const [value, setValue] = useState('');
  const [color, setColor] = useState('#1392ec');
  const [generatedUrl, setGeneratedUrl] = useState<string | null>(null);

  const handleGenerate = () => {
    if (!value) return;
    // Using a reliable public QR API for generation
    const encodedValue = encodeURIComponent(value);
    const qrUrl = `https://api.qrserver.com/v1/create-qr-code/?size=300x300&color=${color.replace('#', '')}&data=${encodedValue}`;
    setGeneratedUrl(qrUrl);
  };

  const types = [
    { id: QRType.URL, icon: 'link', label: 'URL' },
    { id: QRType.WIFI, icon: 'wifi', label: 'Wi-Fi' },
    { id: QRType.TEXT, icon: 'textsms', label: 'Text' },
    { id: QRType.CONTACT, icon: 'contact_page', label: 'Contact' },
    { id: QRType.WHATSAPP, icon: 'chat', label: 'WA' },
  ];

  const colors = ['#1392ec', '#f43f5e', '#10b981', '#f59e0b', '#8b5cf6', '#ffffff'];

  return (
    <div className="h-full overflow-y-auto hide-scrollbar bg-background-dark p-6">
      <header className="flex justify-between items-center py-6 mb-4">
        <div>
          <h1 className="text-2xl font-bold tracking-tight">QR Generator</h1>
          <p className="text-primary text-sm font-medium">Somiddho Pro</p>
        </div>
        <button className="w-10 h-10 rounded-full bg-primary/10 flex items-center justify-center text-primary">
          <span className="material-icons-round">auto_fix_high</span>
        </button>
      </header>

      {/* Type Selector */}
      <section className="mb-8">
        <h2 className="text-xs font-bold uppercase tracking-widest text-white/40 mb-4 px-1">Select Type</h2>
        <div className="flex gap-4 overflow-x-auto hide-scrollbar -mx-6 px-6">
          {types.map((t) => (
            <div key={t.id} className="flex-shrink-0 flex flex-col items-center gap-2">
              <button 
                onClick={() => setType(t.id)}
                className={`w-16 h-16 rounded-2xl flex items-center justify-center transition-all ${type === t.id ? 'bg-primary text-white shadow-lg shadow-primary/30 scale-105' : 'bg-white/5 text-white/40 hover:bg-white/10'}`}
              >
                <span className="material-icons-round text-3xl">{t.icon}</span>
              </button>
              <span className={`text-xs font-medium ${type === t.id ? 'text-primary' : 'text-white/40'}`}>{t.label}</span>
            </div>
          ))}
        </div>
      </section>

      {/* Input Field */}
      <section className="mb-8">
        <div className="glass-panel rounded-2xl p-5">
          <label className="block text-xs font-bold uppercase tracking-widest text-white/40 mb-3">Content Input</label>
          <div className="relative">
            {type === QRType.URL && <span className="absolute left-4 top-1/2 -translate-y-1/2 text-primary font-medium">https://</span>}
            <input 
              className={`w-full bg-white/5 border-white/10 rounded-xl py-4 pr-4 focus:ring-2 focus:ring-primary text-white placeholder-white/20 transition-all ${type === QRType.URL ? 'pl-[72px]' : 'pl-4'}`}
              placeholder={type === QRType.URL ? 'example.com' : 'Enter text here...'}
              type="text"
              value={value}
              onChange={(e) => setValue(e.target.value)}
            />
          </div>
          <p className="mt-3 text-[10px] text-white/30 italic">AI-Optimization: Auto-shortening enabled for analytics.</p>
        </div>
      </section>

      {/* Customization */}
      <section className="space-y-6 mb-32">
        <h2 className="text-xs font-bold uppercase tracking-widest text-white/40 px-1">Customization</h2>

        <div className="glass-panel rounded-2xl p-4 flex items-center justify-between">
          <div className="flex items-center gap-3">
            <div className="w-10 h-10 rounded-lg bg-primary/20 flex items-center justify-center text-primary">
              <span className="material-icons-round">palette</span>
            </div>
            <div>
              <p className="text-sm font-semibold">QR Color</p>
              <p className="text-[11px] text-white/40 uppercase">{color}</p>
            </div>
          </div>
          <div className="flex gap-2">
            {colors.map((c) => (
              <button 
                key={c}
                onClick={() => setColor(c)}
                className={`w-6 h-6 rounded-full border-2 transition-transform ${color === c ? 'scale-125 border-white' : 'border-transparent'}`}
                style={{ backgroundColor: c }}
              />
            ))}
          </div>
        </div>

        {/* Action Button */}
        <button 
          onClick={handleGenerate}
          className="w-full bg-primary hover:bg-primary/90 text-white font-bold py-4 rounded-2xl shadow-xl shadow-primary/30 flex items-center justify-center gap-2 transition-all active:scale-[0.98]"
        >
          <span className="material-icons-round">qr_code_2</span>
          <span>Generate QR Code</span>
        </button>

        {generatedUrl && (
          <div className="mt-8 flex flex-col items-center gap-6 p-6 glass-panel rounded-3xl animate-in zoom-in-95 duration-500">
            <div className="bg-white p-4 rounded-2xl shadow-2xl">
              <img src={generatedUrl} alt="Generated QR" className="w-48 h-48" />
            </div>
            <div className="flex gap-4 w-full">
              <button className="flex-1 bg-white/10 py-3 rounded-xl text-xs font-bold uppercase tracking-wider hover:bg-white/20">Save Image</button>
              <button className="flex-1 bg-white/10 py-3 rounded-xl text-xs font-bold uppercase tracking-wider hover:bg-white/20">Share</button>
            </div>
          </div>
        )}
      </section>
    </div>
  );
};

export default GeneratorView;

import React from 'react';
import { ScanResult } from '../types';

interface HistoryViewProps {
  history: ScanResult[];
  clearHistory: () => void;
}

const HistoryView: React.FC<HistoryViewProps> = ({ history, clearHistory }) => {
  return (
    <div className="h-full overflow-y-auto hide-scrollbar bg-background-dark p-6">
      <header className="flex justify-between items-center py-6 mb-4">
