import React, { useState, useEffect } from 'react';
import { View, ScanResult } from './types';
import ScannerView from './components/ScannerView';
import GeneratorView from './components/GeneratorView';
import HistoryView from './components/HistoryView';
import SettingsView from './components/SettingsView';
import ResultDetailsView from './components/ResultDetailsView';
import Layout from './components/Layout';

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<View>(View.SCANNER);
  const [history, setHistory] = useState<ScanResult[]>([]);
  const [selectedResult, setSelectedResult] = useState<ScanResult | null>(null);
  const [isDarkMode, setIsDarkMode] = useState(true);

  // Load history from local storage on mount
  useEffect(() => {
    const savedHistory = localStorage.getItem('somiddho_history');
    if (savedHistory) {
      setHistory(JSON.parse(savedHistory));
    }
  }, []);

  // Save history to local storage when it changes
  useEffect(() => {
    localStorage.setItem('somiddho_history', JSON.stringify(history));
  }, [history]);

  const handleScanComplete = (result: ScanResult) => {
    setHistory(prev => [result, ...prev].slice(0, 50));
    setSelectedResult(result);
    setCurrentView(View.RESULT_DETAILS);
  };

  const handleSelectFromHistory = (result: ScanResult) => {
    setSelectedResult(result);
    setCurrentView(View.RESULT_DETAILS);
  };

  const renderView = () => {
    switch (currentView) {
      case View.SCANNER:
        return <ScannerView onResult={handleScanComplete} lastScan={history[0]} />;
      case View.GENERATOR:
        return <GeneratorView />;
      case View.HISTORY:
        return <HistoryView history={history} onSelectItem={handleSelectFromHistory} clearHistory={() => setHistory([])} />;
      case View.SETTINGS:
        return <SettingsView isDarkMode={isDarkMode} setIsDarkMode={setIsDarkMode} />;
      case View.RESULT_DETAILS:
        return selectedResult ? (
          <ResultDetailsView 
            result={selectedResult} 
            onBack={() => setCurrentView(View.SCANNER)} 
          />
        ) : (
          <ScannerView onResult={handleScanComplete} lastScan={history[0]} />
        );
      default:
        return <ScannerView onResult={handleScanComplete} lastScan={history[0]} />;
    }
  };

  return (
    <Layout currentView={currentView} setView={setCurrentView}>
      {renderView()}
    </Layout>
  );
};

export default App;

