    2. A trust score from 0 to 100 based on potential risk (100 is perfectly safe).
    3. Three specific safety bullet points (e.g., SSL status, known phishing lists, content type).
    Return the response in JSON format.`;

    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: imageUrl ? {
          parts: [
              { inlineData: { mimeType: 'image/jpeg', data: imageUrl.split(',')[1] } },
              { text: prompt }
          ]
      } : prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            summary: { type: Type.STRING },
            trustScore: { type: Type.NUMBER },
            safetyPoints: { 
              type: Type.ARRAY,
              items: { type: Type.STRING }
            }
          },
          required: ["summary", "trustScore", "safetyPoints"]
        }
      }
    });

    const json = JSON.parse(response.text || "{}");
    return json;
  } catch (error) {
    console.error("Gemini Analysis Error:", error);
    return {
      summary: "Could not perform deep analysis. Proceed with caution.",
      trustScore: 50,
      safetyPoints: ["Analysis failed", "Manual verification required", "Potential connection issue"]
    };
  }
}

import React, { useRef, useEffect, useState, useCallback } from 'react';
