import React, { useState } from 'react';
import { QRType } from '../types';

const GeneratorView: React.FC = () => {
  const [type, setType] = useState<QRType>(QRType.URL);
  const [value, setValue] = useState('');
  const [color, setColor] = useState('#1392ec');
  const [generatedUrl, setGeneratedUrl] = useState<string | null>(null);
  const [isGenerating, setIsGenerating] = useState(false);

  const handleGenerate = () => {
    if (!value) return;
    setIsGenerating(true);
    // Using a reliable public QR API for generation
    const encodedValue = encodeURIComponent(value);
    const qrUrl = `https://api.qrserver.com/v1/create-qr-code/?size=500x500&color=${color.replace('#', '')}&data=${encodedValue}`;

    // Preload image to ensure it's ready
    const img = new Image();
    img.onload = () => {
      setGeneratedUrl(qrUrl);
      setIsGenerating(false);
    };
    img.src = qrUrl;
  };

  const handleSaveImage = async () => {
    if (!generatedUrl) return;
    try {
      const response = await fetch(generatedUrl);
      const blob = await response.blob();
      const url = window.URL.createObjectURL(blob);
      const link = document.createElement('a');
      link.href = url;
      link.download = `somiddho-qr-${Date.now()}.png`;
      document.body.appendChild(link);
      link.click();
      document.body.removeChild(link);
      window.URL.revokeObjectURL(url);
    } catch (err) {
      console.error("Save error:", err);
      alert("Failed to save image.");
    }
  };

  const handleShare = async () => {
    if (!generatedUrl) return;
    const shareData = {
      title: 'Somiddho QR Code',
      text: `Scan this QR code: ${value}`,
      url: generatedUrl
    };

    if (navigator.share) {
      try {
        await navigator.share(shareData);
      } catch (err) {
        console.warn("Share failed or cancelled", err);
      }
    } else {
      // Fallback: Copy content to clipboard
      try {
        await navigator.clipboard.writeText(value);
        alert("Content copied to clipboard!");
      } catch (err) {
        console.error("Clipboard error:", err);
      }
    }
  };

  const types = [
    { id: QRType.URL, icon: 'link', label: 'URL' },
    { id: QRType.WIFI, icon: 'wifi', label: 'Wi-Fi' },
    { id: QRType.TEXT, icon: 'textsms', label: 'Text' },
    { id: QRType.CONTACT, icon: 'contact_page', label: 'Contact' },
    { id: QRType.WHATSAPP, icon: 'chat', label: 'WA' },
  ];

  const colors = ['#1392ec', '#f43f5e', '#10b981', '#f59e0b', '#8b5cf6', '#ffffff'];

  return (
    <div className="h-full overflow-y-auto hide-scrollbar bg-background-dark p-6">
