      </header>

      {/* Type Selector */}
      <section className="mb-8">
        <h2 className="text-xs font-bold uppercase tracking-widest text-white/40 mb-4 px-1">Select Type</h2>
        <div className="flex gap-4 overflow-x-auto hide-scrollbar -mx-6 px-6">
          {types.map((t) => (
            <div key={t.id} className="flex-shrink-0 flex flex-col items-center gap-2">
              <button 
                onClick={() => setType(t.id)}
                className={`w-16 h-16 rounded-2xl flex items-center justify-center transition-all ${type === t.id ? 'bg-primary text-white shadow-lg shadow-primary/30 scale-105' : 'bg-white/5 text-white/40 hover:bg-white/10'}`}
              >
