    localStorage.setItem('somiddho_history', JSON.stringify(history));
  }, [history]);

  const playBeep = () => {
    if (!soundOnScan) return;
    try {
      const audioCtx = new (window.AudioContext || (window as any).webkitAudioContext)();
      const oscillator = audioCtx.createOscillator();
      const gainNode = audioCtx.createGain();
      oscillator.connect(gainNode);
      gainNode.connect(audioCtx.destination);
      oscillator.type = 'sine';
      oscillator.frequency.setValueAtTime(880, audioCtx.currentTime);
      gainNode.gain.setValueAtTime(0, audioCtx.currentTime);
      gainNode.gain.linearRampToValueAtTime(0.2, audioCtx.currentTime + 0.05);
      gainNode.gain.linearRampToValueAtTime(0, audioCtx.currentTime + 0.2);
      oscillator.start();
      oscillator.stop(audioCtx.currentTime + 0.2);
    } catch (e) {
      console.warn("Audio feedback failed:", e);
    }
  };

  const handleScanComplete = (result: ScanResult) => {
    // Feedback
    if (vibrateOnScan && navigator.vibrate) navigator.vibrate(100);
    if (soundOnScan) playBeep();

    setHistory(prev => [result, ...prev].slice(0, 50));

    if (autoOpenUrl && result.data.startsWith('http')) {
      window.open(result.data, '_blank');
    } else {
      setSelectedResult(result);
      setCurrentView(View.RESULT_DETAILS);
    }
  };

  const handleReset = () => {
    if (confirm("Are you sure you want to reset all data and settings?")) {
      setHistory([]);
      setVibrateOnScan(true);
      setSoundOnScan(true);
      setAutoOpenUrl(false);
      setThemeColor('#0df259');
      localStorage.clear();
      alert("App data reset successful.");
    }
  };

  const renderView = () => {
    switch (currentView) {
      case View.SCANNER:
        return <ScannerView onResult={handleScanComplete} lastScan={history[0]} />;
      case View.GENERATOR:
        return <GeneratorView />;
      case View.HISTORY:
        return <HistoryView history={history} onSelectItem={(res) => { setSelectedResult(res); setCurrentView(View.RESULT_DETAILS); }} clearHistory={() => setHistory([])} />;
      case View.SETTINGS:
        return (
          <SettingsView 
            vibrate={vibrateOnScan} setVibrate={setVibrateOnScan}
            sound={soundOnScan} setSound={setSoundOnScan}
            autoOpen={autoOpenUrl} setAutoOpen={setAutoOpenUrl}
            theme={themeColor} setTheme={setThemeColor}
            onReset={handleReset}
          />
        );
      case View.RESULT_DETAILS:
        return selectedResult ? (
          <ResultDetailsView result={selectedResult} onBack={() => setCurrentView(View.SCANNER)} />
        ) : <ScannerView onResult={handleScanComplete} />;
      default:
        return <ScannerView onResult={handleScanComplete} />;
    }
  };

  return (
    <Layout currentView={currentView} setView={setCurrentView}>
      {renderView()}
    </Layout>
  );
};

