      case View.TERMS:
        return <LegalView title="Terms & Conditions" content={<TermsContent />} onBack={() => setCurrentView(View.SETTINGS)} />;
      default:
        return <ScannerView onResult={handleScanComplete} />;
    }
  };

  return (
    <Layout currentView={currentView} setView={setCurrentView}>
      {renderView()}
    </Layout>
  );
