import React, { useRef, useEffect, useState, useCallback } from 'react';
import jsQR from 'jsqr';
import { ScanResult } from '../types';

interface ScannerViewProps {
  onResult: (result: ScanResult) => void;
  lastScan?: ScanResult;
}

const ScannerView: React.FC<ScannerViewProps> = ({ onResult, lastScan }) => {
  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [stream, setStream] = useState<MediaStream | null>(null);
  const [isProcessing, setIsProcessing] = useState(false);
  const [flashOn, setFlashOn] = useState(false);
  const [zoom, setZoom] = useState(1);
  const [cameraError, setCameraError] = useState<string | null>(null);
  const [scanPaused, setScanPaused] = useState(false);

  useEffect(() => {
    async function setupCamera() {
      setCameraError(null);
      try {
        const mediaStream = await navigator.mediaDevices.getUserMedia({
          video: { facingMode: 'environment' }
        });
        setStream(mediaStream);
        if (videoRef.current) {
          videoRef.current.srcObject = mediaStream;
        }
      } catch (err: any) {
        setCameraError(err.message || "Camera not found");
      }
    }
    setupCamera();
    return () => {
      if (stream) {
        stream.getTracks().forEach(track => track.stop());
      }
    };
  }, []);

  useEffect(() => {
    if (stream) {
      const videoTrack = stream.getVideoTracks()[0];
      if (videoTrack) {
        const capabilities = videoTrack.getCapabilities() as any;
        if (capabilities.zoom) {
          videoTrack.applyConstraints({ advanced: [{ zoom: zoom }] } as any);
        }
      }
    }
  }, [zoom, stream]);

  const captureFrame = useCallback(() => {
    if (!videoRef.current || !canvasRef.current) return null;
    const canvas = canvasRef.current;
    const video = videoRef.current;
    canvas.width = video.videoWidth;
    canvas.height = video.videoHeight;
    const ctx = canvas.getContext('2d');
    if (ctx) {
      ctx.drawImage(video, 0, 0, canvas.width, canvas.height);
      return canvas.toDataURL('image/jpeg', 0.8);
    }
    return null;
  }, []);

  const handleScanSuccess = (data: string) => {
    if (isProcessing || scanPaused) return;
    setScanPaused(true);
    setIsProcessing(true);

    const imageData = captureFrame();

    const result: ScanResult = {
      id: Date.now().toString(),
      data: data,
      timestamp: Date.now(),
      type: data.startsWith('http') ? 'URL' : 'TEXT',
      imageUrl: imageData || undefined
    };

    onResult(result);
    setIsProcessing(false);

    setTimeout(() => setScanPaused(false), 2000);
  };

  useEffect(() => {
    let requestRef: number;
    const scanFrame = () => {
      if (videoRef.current && videoRef.current.readyState === videoRef.current.HAVE_ENOUGH_DATA && !scanPaused) {
        const canvas = canvasRef.current;
        if (canvas) {
          const ctx = canvas.getContext('2d');
          if (ctx) {
            canvas.width = videoRef.current.videoWidth;
            canvas.height = videoRef.current.videoHeight;
            ctx.drawImage(videoRef.current, 0, 0, canvas.width, canvas.height);
            const imageData = ctx.getImageData(0, 0, canvas.width, canvas.height);
            const code = jsQR(imageData.data, imageData.width, imageData.height);
            if (code) handleScanSuccess(code.data);
          }
        }
      }
      requestRef = requestAnimationFrame(scanFrame);
    };
    requestRef = requestAnimationFrame(scanFrame);
    return () => cancelAnimationFrame(requestRef);
  }, [scanPaused]);

  return (
    <div className="relative h-full flex flex-col">
      <div className="absolute inset-0 z-0 bg-black">
        {cameraError ? (
          <div className="flex flex-col items-center justify-center h-full p-10 text-center">
            <span className="material-icons-round text-6xl text-white/20 mb-4">videocam_off</span>
            <p className="text-white/40 text-sm">{cameraError}</p>
          </div>
        ) : (
          <video ref={videoRef} autoPlay playsInline className="w-full h-full object-cover opacity-60" />
        )}
        <canvas ref={canvasRef} className="hidden" />
        <div className="absolute inset-0 bg-gradient-to-b from-background-dark/80 via-transparent to-background-dark/90"></div>
      </div>

      <header className="relative z-10 px-6 py-4 flex flex-col gap-6">
        <div className="flex items-center justify-between">
          <div className="flex items-center gap-3">
            <div className="w-10 h-10 rounded-xl bg-primary flex items-center justify-center">
              <span className="material-icons-round text-black">qr_code_scanner</span>
            </div>
            <div>
              <h1 className="text-xl font-bold tracking-tight">Somiddho</h1>
              <p className="text-[10px] uppercase tracking-widest text-primary/80 font-semibold">Pro Scanner</p>
            </div>
          </div>
          <div className="flex items-center gap-2 glass-panel p-1 rounded-full">
            <button onClick={() => setFlashOn(!flashOn)} className={`w-10 h-10 flex items-center justify-center rounded-full transition-colors ${flashOn ? 'bg-primary/20 text-primary' : ''}`}>
              <span className="material-icons-round">{flashOn ? 'flash_on' : 'flash_off'}</span>
            </button>
          </div>
        </div>
      </header>

