import React, { useRef, useEffect, useState, useCallback } from 'react';
import jsQR from 'jsqr';
import { ScanResult } from '../types';

interface ScannerViewProps {
  onResult: (result: ScanResult) => void;
  lastScan?: ScanResult;
}

const ScannerView: React.FC<ScannerViewProps> = ({ onResult, lastScan }) => {
  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [stream, setStream] = useState<MediaStream | null>(null);
  const [isProcessing, setIsProcessing] = useState(false);
  const [flashOn, setFlashOn] = useState(false);
  const [zoom, setZoom] = useState(1);
  const [cameraError, setCameraError] = useState<string | null>(null);
  const [scanPaused, setScanPaused] = useState(false);

  useEffect(() => {
    async function setupCamera() {
      setCameraError(null);
      try {
        const mediaStream = await navigator.mediaDevices.getUserMedia({
          video: { facingMode: 'environment' }
        });
        setStream(mediaStream);
        if (videoRef.current) {
          videoRef.current.srcObject = mediaStream;
        }
      } catch (err: any) {
        setCameraError(err.message || "Camera not found");
      }
    }
    setupCamera();
    return () => {
      if (stream) {
        stream.getTracks().forEach(track => track.stop());
      }
    };
  }, []);

  useEffect(() => {
    if (stream) {
      const videoTrack = stream.getVideoTracks()[0];
      if (videoTrack) {
        const capabilities = videoTrack.getCapabilities() as any;
        if (capabilities.zoom) {
          videoTrack.applyConstraints({ advanced: [{ zoom: zoom }] } as any);
        }
      }
    }
  }, [zoom, stream]);

  const captureFrame = useCallback(() => {
    if (!videoRef.current || !canvasRef.current) return null;
    const canvas = canvasRef.current;
    const video = videoRef.current;
    canvas.width = video.videoWidth;
    canvas.height = video.videoHeight;
    const ctx = canvas.getContext('2d');
    if (ctx) {
      ctx.drawImage(video, 0, 0, canvas.width, canvas.height);
      return canvas.toDataURL('image/jpeg', 0.8);
    }
    return null;
  }, []);

  const handleScanSuccess = (data: string) => {
    if (isProcessing || scanPaused) return;
    setScanPaused(true);
    setIsProcessing(true);

    const imageData = captureFrame();

    const result: ScanResult = {
      id: Date.now().toString(),
      data: data,
      timestamp: Date.now(),
      type: data.startsWith('http') ? 'URL' : 'TEXT',
      imageUrl: imageData || undefined
    };

    onResult(result);
    setIsProcessing(false);

    setTimeout(() => setScanPaused(false), 2000);
  };

  useEffect(() => {
    let requestRef: number;
    const scanFrame = () => {
      if (videoRef.current && videoRef.current.readyState === videoRef.current.HAVE_ENOUGH_DATA && !scanPaused) {
        const canvas = canvasRef.current;
        if (canvas) {
          const ctx = canvas.getContext('2d');
          if (ctx) {
            canvas.width = videoRef.current.videoWidth;
            canvas.height = videoRef.current.videoHeight;
            ctx.drawImage(videoRef.current, 0, 0, canvas.width, canvas.height);
            const imageData = ctx.getImageData(0, 0, canvas.width, canvas.height);
            const code = jsQR(imageData.data, imageData.width, imageData.height);
            if (code) handleScanSuccess(code.data);
          }
        }
      }
      requestRef = requestAnimationFrame(scanFrame);
    };
    requestRef = requestAnimationFrame(scanFrame);
    return () => cancelAnimationFrame(requestRef);
  }, [scanPaused]);

  return (
    <div className="relative h-full flex flex-col">
      {/* Background Camera Feed */}
      <div className="absolute inset-0 z-0 bg-black">
        {cameraError ? (
          <div className="flex flex-col items-center justify-center h-full p-10 text-center">
            <span className="material-icons-round text-6xl text-white/10 mb-4">videocam_off</span>
            <p className="text-white/30 text-xs font-medium uppercase tracking-widest">{cameraError}</p>
          </div>
        ) : (
          <video ref={videoRef} autoPlay playsInline className="w-full h-full object-cover opacity-60" />
        )}
        <canvas ref={canvasRef} className="hidden" />
        <div className="absolute inset-0 bg-gradient-to-b from-black/60 via-transparent to-black/80"></div>
      </div>

      {/* Top Header */}
      <header className="relative z-10 px-6 py-6 flex items-center justify-between">
        <div className="flex items-center gap-3">
          <div className="w-10 h-10 rounded-xl bg-primary flex items-center justify-center shadow-[0_0_20px_rgba(var(--primary-rgb),0.3)]">
            <span className="material-icons-round text-black text-xl">qr_code_scanner</span>
          </div>
          <div>
            <h1 className="text-lg font-bold leading-none">Somiddho</h1>
            <p className="text-[9px] uppercase tracking-[0.2em] text-primary font-bold mt-1">Pro Scanner</p>
          </div>
        </div>
        <button 
          onClick={() => setFlashOn(!flashOn)} 
          className={`w-12 h-12 flex items-center justify-center rounded-full glass-panel transition-all active:scale-90 ${flashOn ? 'text-primary border-primary/40 bg-primary/10' : 'text-white/40'}`}
        >
          <span className="material-icons-round text-xl">{flashOn ? 'flash_on' : 'flash_off'}</span>
        </button>
      </header>

      {/* Viewfinder */}
      <main className="relative z-10 flex-1 flex flex-col items-center justify-center">
        <div className="relative w-64 h-64 sm:w-80 sm:h-80 transition-all duration-500">
          {/* HUD Corners */}
          <div className="hud-corner top-0 left-0 border-t-4 border-l-4 rounded-tl-2xl shadow-[0_0_10px_var(--primary-color)]"></div>
          <div className="hud-corner top-0 right-0 border-t-4 border-r-4 rounded-tr-2xl shadow-[0_0_10px_var(--primary-color)]"></div>
          <div className="hud-corner bottom-0 left-0 border-b-4 border-l-4 rounded-bl-2xl shadow-[0_0_10px_var(--primary-color)]"></div>
          <div className="hud-corner bottom-0 right-0 border-b-4 border-r-4 rounded-br-2xl shadow-[0_0_10px_var(--primary-color)]"></div>

          {/* Scanning Animation */}
          <div className="scanner-line opacity-60"></div>

          {/* Center Guide Icon */}
          <div className="absolute inset-0 flex items-center justify-center opacity-10">
            <span className="material-icons-round text-8xl">filter_center_focus</span>
          </div>
        </div>

        <p className="mt-8 text-white/30 text-[10px] font-bold uppercase tracking-[0.3em] animate-pulse">
          Align QR code to scan
        </p>

        {/* Professional Zoom Control Area */}
        <div className="mt-auto w-full px-6 pb-8 space-y-6">
          <div className="bg-black/60 backdrop-blur-2xl rounded-[2.5rem] p-6 border border-white/5 shadow-2xl">
            {/* Quick Presets (iPhone Camera Style) */}
            <div className="flex justify-center gap-4 mb-6">
              {[1, 2, 5].map((val) => (
                <button
                  key={val}
                  onClick={() => setZoom(val)}
                  className={`w-11 h-11 rounded-full flex items-center justify-center transition-all duration-300 transform active:scale-90 ${zoom === val ? 'bg-primary text-black font-bold shadow-lg shadow-primary/30 scale-110' : 'bg-white/5 text-white/40 hover:bg-white/10'}`}
                >
                  <span className="text-[11px] uppercase font-black">{val}x</span>
                </button>
              ))}
            </div>

            {/* Smooth Slider Control */}
            <div className="flex items-center gap-4">
              <span className="material-icons-round text-white/20 text-sm">remove</span>
              <div className="relative flex-1 flex items-center">
                <input 
                  type="range" 
                  min="1" 
                  max="10" 
                  step="0.1" 
                  value={zoom} 
                  onChange={(e) => setZoom(parseFloat(e.target.value))} 
                  className="w-full accent-primary h-1.5 bg-white/10 rounded-full appearance-none cursor-pointer transition-all hover:bg-white/20" 
                />
              </div>
              <span className="material-icons-round text-white/20 text-sm">add</span>
            </div>

            <div className="text-center mt-4">
              <span className="text-[10px] font-black text-primary tracking-[0.4em] uppercase opacity-80">{zoom.toFixed(1)}x ZOOM</span>
            </div>
          </div>
        </div>
      </main>

      {/* Last Scan Floating Preview */}
      {lastScan && (
        <footer className="relative z-10 px-6 pb-6">
          <div className="glass-panel p-3 rounded-2xl flex items-center gap-4 border-white/5 shadow-2xl animate-in slide-in-from-bottom-4 duration-500">
            <div className="w-12 h-12 rounded-xl bg-primary/20 flex items-center justify-center overflow-hidden shrink-0">
              {lastScan.imageUrl ? (
                <img src={lastScan.imageUrl} className="w-full h-full object-cover" />
              ) : (
                <span className="material-icons-round text-primary">qr_code_2</span>
              )}
            </div>
            <div className="flex-1 min-w-0">
              <p className="text-[9px] text-primary font-black uppercase tracking-widest">Recent Activity</p>
              <p className="text-xs font-bold text-white/80 truncate mt-0.5">{lastScan.data}</p>
            </div>
            <div className="w-8 h-8 rounded-full bg-white/5 flex items-center justify-center">
               <span className="material-icons-round text-white/20 text-sm">chevron_right</span>
            </div>
          </div>
        </footer>
      )}
    </div>
  );
};

