  return (
    <div className="h-full overflow-y-auto bg-background-dark text-white flex flex-col font-display">
      <header className="px-6 py-4 flex items-center justify-between sticky top-0 z-50 bg-background-dark/80 backdrop-blur-xl border-b border-white/5 no-print">
        <button onClick={onBack} className="w-10 h-10 flex items-center justify-start text-white/40">
