        <h1 className="text-lg font-bold">Scan Result</h1>
        <button onClick={() => setIsFavorited(!isFavorited)} className={`w-10 h-10 flex items-center justify-end ${isFavorited ? 'text-primary' : 'text-white/40'}`}>
          <span className="material-icons-round">{isFavorited ? 'star' : 'star_outline'}</span>
        </button>
      </header>

      <main className="flex-1 px-6 pb-40 space-y-6 pt-6">
        <section className="glass-panel rounded-[2.5rem] border border-white/5 overflow-hidden shadow-2xl">
          <div className="aspect-video w-full bg-white/5 flex items-center justify-center overflow-hidden relative">
            {result.imageUrl ? <img src={result.imageUrl} className="w-full h-full object-cover" alt="Scanned" /> : <span className="material-icons-round text-6xl text-white/10">qr_code_2</span>}
            <div className="absolute top-4 right-4 bg-primary text-black text-[10px] font-black px-3 py-1.5 rounded-full uppercase tracking-widest shadow-lg no-print">
              {result.type}
            </div>
          </div>
          <div className="p-8">
            <p className="text-[10px] uppercase font-bold text-white/30 mb-2 tracking-[0.2em]">Content Details</p>
            <p className="text-xl font-bold break-all text-white leading-tight">{result.data}</p>
            <p className="text-[10px] text-white/20 mt-4 uppercase tracking-widest">{new Date(result.timestamp).toLocaleString()}</p>
