        <section className="no-print">
          <button onClick={handleShare} className="w-full p-5 glass-panel rounded-[2rem] border border-white/5 flex items-center justify-center gap-3 active:scale-95 transition-transform">
             <span className="material-icons-round text-primary">share</span>
             <span className="text-[10px] font-black uppercase tracking-widest">Share Result</span>
          </button>
        </section>

        <section className="glass-panel p-6 rounded-[2rem] border border-white/5">
          <div className="flex items-center gap-3 mb-2">
            <span className="material-icons-round text-white/20">privacy_tip</span>
            <p className="text-[10px] font-bold uppercase tracking-widest text-white/30">Privacy Note</p>
          </div>
          <p className="text-xs text-white/50 leading-relaxed">
            This QR code was processed locally. You can download the result as a PDF for your records using the button above.
          </p>
        </section>
      </main>

      <footer className="fixed bottom-0 left-0 right-0 p-6 bg-background-dark/95 backdrop-blur-2xl border-t border-white/5 z-50 no-print">
        <button onClick={handleAction} className="w-full h-16 bg-primary text-black font-black rounded-2xl flex items-center justify-center gap-2 active:scale-95 transition-transform shadow-[0_10px_40px_rgba(13,242,89,0.3)] uppercase tracking-[0.2em] text-sm">
          <span className="material-icons-round">{isUrl ? 'open_in_new' : 'search'}</span>
          {isUrl ? 'Open in Browser' : 'Search on Web'}
        </button>
      </footer>
    </div>
  );
};

