import { ScanResult } from '../types';

interface ResultDetailsViewProps {
  result: ScanResult;
  onBack: () => void;
  onToggleFavorite: (id: string) => void;
}

const ResultDetailsView: React.FC<ResultDetailsViewProps> = ({ result, onBack, onToggleFavorite }) => {
  const [copySuccess, setCopySuccess] = useState(false);

  const isUrl = result.data.trim().toLowerCase().startsWith('http');

  const handleAction = () => {
    if (isUrl) {
      window.open(result.data, '_blank', 'noopener,noreferrer');
    } else {
      window.open(`https://www.google.com/search?q=${encodeURIComponent(result.data)}`, '_blank');
    }
  };

  const handleCopy = async () => {
    try {
      await navigator.clipboard.writeText(result.data);
      setCopySuccess(true);
      setTimeout(() => setCopySuccess(false), 2000);
    } catch (err) { console.error(err); }
  };

  const handlePrint = () => {
    window.print();
  };

  const handleShare = async () => {
    if (navigator.share) {
      try {
        await navigator.share({
          title: 'Scanned Content',
          text: result.data,
          url: isUrl ? result.data : undefined
        });
      } catch (e) { console.error(e); }
    } else {
      handleCopy();
      alert("Link copied to share!");
    }
  };

  return (
    <div className="h-full overflow-y-auto bg-background-dark text-white flex flex-col font-display">
      <header className="px-6 py-4 flex items-center justify-between sticky top-0 z-50 bg-background-dark/80 backdrop-blur-xl border-b border-white/5 no-print">
        <button onClick={onBack} className="w-10 h-10 flex items-center justify-start text-white/40">
          <span className="material-icons-round">arrow_back_ios</span>
        </button>
        <h1 className="text-lg font-bold">Scan Result</h1>
        <button onClick={() => onToggleFavorite(result.id)} className={`w-10 h-10 flex items-center justify-end transition-colors ${result.isFavorite ? 'text-primary' : 'text-white/40'}`}>
          <span className="material-icons-round">{result.isFavorite ? 'star' : 'star_outline'}</span>
        </button>
      </header>

      <main className="flex-1 px-6 pb-40 space-y-6 pt-6">
        <section className="glass-panel rounded-[2.5rem] border border-white/5 overflow-hidden shadow-2xl">
          <div className="aspect-video w-full bg-white/5 flex items-center justify-center overflow-hidden relative">
            {result.imageUrl ? <img src={result.imageUrl} className="w-full h-full object-cover" alt="Scanned" /> : <span className="material-icons-round text-6xl text-white/10">qr_code_2</span>}
            <div className="absolute top-4 right-4 bg-primary text-black text-[10px] font-black px-3 py-1.5 rounded-full uppercase tracking-widest shadow-lg no-print">
              {result.type}
            </div>
          </div>
          <div className="p-8">
            <p className="text-[10px] uppercase font-bold text-white/30 mb-2 tracking-[0.2em]">Content Details</p>
            <p className="text-xl font-bold break-all text-white leading-tight">{result.data}</p>
            <p className="text-[10px] text-white/20 mt-4 uppercase tracking-widest">{new Date(result.timestamp).toLocaleString()}</p>
          </div>
        </section>

        <section className="grid grid-cols-2 gap-4 no-print">
          <button onClick={handleCopy} className={`p-5 rounded-[2rem] border transition-all flex flex-col items-center gap-2 ${copySuccess ? 'border-primary bg-primary/10 text-primary' : 'glass-panel border-white/5'}`}>
            <span className="material-icons-round">{copySuccess ? 'check' : 'content_copy'}</span>
            <span className="text-[10px] font-black uppercase tracking-widest">Copy Content</span>
          </button>
          <button onClick={handlePrint} className="p-5 rounded-[2rem] glass-panel border border-white/5 flex flex-col items-center gap-2 active:bg-white/10 transition-colors">
            <span className="material-icons-round">picture_as_pdf</span>
            <span className="text-[10px] font-black uppercase tracking-widest">Download PDF</span>
          </button>
        </section>

        <section className="no-print">
          <button onClick={handleShare} className="w-full p-5 glass-panel rounded-[2rem] border border-white/5 flex items-center justify-center gap-3 active:scale-95 transition-transform">
             <span className="material-icons-round text-primary">share</span>
             <span className="text-[10px] font-black uppercase tracking-widest">Share Result</span>
          </button>
        </section>

        <section className="glass-panel p-6 rounded-[2rem] border border-white/5">
          <div className="flex items-center gap-3 mb-2">
            <span className="material-icons-round text-white/20">privacy_tip</span>
            <p className="text-[10px] font-bold uppercase tracking-widest text-white/30">Privacy Note</p>
          </div>
          <p className="text-xs text-white/50 leading-relaxed">
            This QR code was processed locally. You can download the result as a PDF for your records using the button above.
          </p>
        </section>
      </main>

      <footer className="fixed bottom-0 left-0 right-0 p-6 bg-background-dark/95 backdrop-blur-2xl border-t border-white/5 z-50 no-print">
        <button onClick={handleAction} className="w-full h-16 bg-primary text-black font-black rounded-2xl flex items-center justify-center gap-2 active:scale-95 transition-transform shadow-[0_10px_40px_rgba(13,242,89,0.3)] uppercase tracking-[0.2em] text-sm">
          <span className="material-icons-round">{isUrl ? 'open_in_new' : 'search'}</span>
          {isUrl ? 'Open in Browser' : 'Search on Web'}
        </button>
      </footer>
    </div>
  );
};

export default ResultDetailsView;

